/// Derive the ochid path prefix from the repo and other-repo paths.
///
/// The prefix is the workspace-root-relative path to the other repo.
/// We canonicalize both paths to resolve `..` components, then compute
/// the other repo's path relative to the workspace root (app repo parent).
///
/// Examples (from workspace root):
///   repo=`.`, other=`.claude`     â†’ `/.claude/`
///   repo=`.claude`, other=`..`    â†’ `/`
///   repo=`.`, other=`.`           â†’ `/`
fn compute_ochid_prefix(repo_path: &std::path::Path, other_repo_path: &std::path::Path) -> Result<String, Box<dyn std::error::Error>> {
    let repo_canon = std::fs::canonicalize(repo_path)
        .map_err(|e| format!("cannot canonicalize repo path '{}': {e}", repo_path.display()))?;
    let other_canon = std::fs::canonicalize(other_repo_path)
        .map_err(|e| format!("cannot canonicalize other-repo path '{}': {e}", other_repo_path.display()))?;

    // The workspace root is the app repo. If -R points to a subdirectory
    // (like .claude), the workspace root is its parent. We determine this
    // by finding the common ancestor: the workspace root is always the
    // shorter (or equal) of the two canonical paths, assuming one is a
    // subdirectory of the other or they are the same.
    //
    // Simpler approach: compute other_canon relative to repo_canon's parent
    // (if repo is a subdir) or repo_canon itself (if repo is the root).
    // Actually, the ochid prefix is always relative to the workspace root,
    // and the workspace root is the *outermost* of the two repos.

    // Find the workspace root: whichever canonical path is a prefix of the other
    // (or they're the same, meaning workspace root = both).
    let workspace_root = if other_canon.starts_with(&repo_canon) {
        &repo_canon
    } else if repo_canon.starts_with(&other_canon) {
        &other_canon
    } else {
        return Err(format!(
            "repos are not nested: '{}' and '{}'",
            repo_canon.display(),
            other_canon.display()
        ).into());
    };

    let relative = other_canon.strip_prefix(workspace_root)
        .map_err(|e| format!("cannot compute relative path: {e}"))?;

    let rel_str = relative.to_string_lossy();
    if rel_str.is_empty() {
        Ok("/".to_string())
    } else {
        Ok(format!("/{rel_str}/"))
    }
}

