            val
        };

        let post_issues = if let Some(ref v) = fixed_ochid {
            validate_ochid(v, &other_prefix, args.id_len, &other_workspace, &other_repo)
        } else {
            OchidIssues {
                wrong_prefix: false,
                wrong_length: false,
                not_found: true,
            }
